    34→  useEffect(() => {
    35→    const observer = new IntersectionObserver((entries) => {
    36→      if (entries[0].isIntersecting && !hasAnimated) {
    37→        setHasAnimated(true);
    38→        let startTimestamp: number | null = null;
    39→        const step = (timestamp: number) => {
    40→          if (!startTimestamp) startTimestamp = timestamp;
    41→          const progress = Math.min((timestamp - startTimestamp) / duration, 1);
    42→          setCount(Math.floor(progress * end));
    43→          if (progress < 1) {
    44→            window.requestAnimationFrame(step);
    45→          }
    46→        };
